/**
 * Nearest civic address. `text` is the street + number; `secondary` is the
 * post code + post town (e.g. "2686 LOM").
 */
public struct Address {
    public var text: String
    public var secondary: String?

    // Default memberwise initializers are never public by default, so we
    // declare one manually.
    public init(text: String, secondary: String?) {
        self.text = text
        self.secondary = secondary
    }
}



extension Address: Equatable, Hashable {
    public static func ==(lhs: Address, rhs: Address) -> Bool {
        if lhs.text != rhs.text {
            return false
        }
        if lhs.secondary != rhs.secondary {
            return false
        }
        return true
    }

    public func hash(into hasher: inout Hasher) {
        hasher.combine(text)
        hasher.combine(secondary)
    }
}


