/**
 * Errors surfaced across the FFI boundary.
 */
public enum EngineError {

    
    
    /**
     * `from_ruleset_json` was given a ruleset that didn't parse.
     */
    case InvalidRuleset(message: String
    )
}


#if swift(>=5.8)
@_documentation(visibility: private)
#endif
public struct FfiConverterTypeEngineError: FfiConverterRustBuffer {
    typealias SwiftType = EngineError

    public static func read(from buf: inout (data: Data, offset: Data.Index)) throws -> EngineError {
        let variant: Int32 = try readInt(&buf)
        switch variant {

        

        
        case 1: return .InvalidRuleset(
            message: try FfiConverterString.read(from: &buf)
            )

         default: throw UniffiInternalError.unexpectedEnumCase
        }
    }

    public static func write(_ value: EngineError, into buf: inout [UInt8]) {
        switch value {

        

        
        
        case let .InvalidRuleset(message):
            writeInt(&buf, Int32(1))
            FfiConverterString.write(message, into: &buf)
            
        }
    }
}


extension EngineError: Equatable, Hashable {}

extension EngineError: Foundation.LocalizedError {
    public var errorDescription: String? {
        String(reflecting: self)
    }
}

// Note that we don't yet support `indirect` for enums.
// See https://github.com/mozilla/uniffi-rs/issues/396 for further discussion.
/**
 * Canonical spatial qualifier (the richer Flutter `LocationQualifier` set).
 * The Android binding folds `CloseTo`→Near and `InArea`→In to match its
 * 4-value `PlaceQualifier`; the UI turns these into localized words.
 */

public enum Qualifier {
    
    /**
     * Standing on the feature (peak / glacier / island).
     */
    case on
    /**
     * Near but outside a point feature (loose peak / farm / water).
     */
    case closeTo
    /**
     * Touching a water body or building.
     */
    case atPlace
    /**
     * Inside a bounded area (settlement / park).
     */
    case inArea
    /**
     * In the wider periphery of a feature.
     */
    case near
}


#if swift(>=5.8)
@_documentation(visibility: private)
#endif
public struct FfiConverterTypeQualifier: FfiConverterRustBuffer {
    typealias SwiftType = Qualifier

    public static func read(from buf: inout (data: Data, offset: Data.Index)) throws -> Qualifier {
        let variant: Int32 = try readInt(&buf)
        switch variant {
        
        case 1: return .on
        
        case 2: return .closeTo
        
        case 3: return .atPlace
        
        case 4: return .inArea
        
        case 5: return .near
        
        default: throw UniffiInternalError.unexpectedEnumCase
        }
    }

    public static func write(_ value: Qualifier, into buf: inout [UInt8]) {
        switch value {
        
        
        case .on:
            writeInt(&buf, Int32(1))
        
        
        case .closeTo:
            writeInt(&buf, Int32(2))
        
        
        case .atPlace:
            writeInt(&buf, Int32(3))
        
        
        case .inArea:
            writeInt(&buf, Int32(4))
        
        
        case .near:
            writeInt(&buf, Int32(5))
        
        }
    }
}


#if swift(>=5.8)
@_documentation(visibility: private)
#endif
